2. Implement `importWorkspace(filePath: string)` main function:
```ts
export async function importWorkspace(filePath: string): Promise<void> {
  // 1. Read and parse imported file
  const resolvedPath = expandTilde(filePath);
  let raw: string;
  try {
    raw = await readFile(resolvedPath, 'utf-8');
  } catch {
    console.error(`Error: Cannot read file: ${resolvedPath}`);
    process.exitCode = 1;
    return;
  }

  let imported: ImportedRegistry;
  try {
    const parsed = yaml.load(raw);
    imported = ReposRegistrySchema.parse(parsed);
  } catch (err) {
    console.error(`Error: Invalid repos.yml format: ${err instanceof Error ? err.message : String(err)}`);
    process.exitCode = 1;
    return;
  }

  // 2. Validate imported file has workspaces
  const workspaceNames = Object.keys(imported.workspaces);
  if (workspaceNames.length === 0) {
    console.error('Error: Imported file contains no workspaces.');
    process.exitCode = 1;
    return;
  }

  // 3. Select which workspace to import (if multiple)
  let selectedWorkspaceName: string;
  if (workspaceNames.length === 1) {
    selectedWorkspaceName = workspaceNames[0];
    console.log(`Importing workspace: ${selectedWorkspaceName}`);
  } else {
    selectedWorkspaceName = await select({
      message: 'Select workspace to import:',
      choices: workspaceNames.map((name) => ({
        name: `${name} (${imported.workspaces[name].repos.length} repos)`,
        value: name,
      })),
    });
  }

  const importedWorkspace = imported.workspaces[selectedWorkspaceName];

  // 4. Prompt for destination (global or project)
  const destination = await promptDestination();

  // 5. Load existing registry at destination (if exists)
  const existingRegistry = await loadReposRegistry(destination.path);

  // 6. Select target workspace (merge into existing or create new)
  const targetWorkspace = await promptTargetWorkspace(
    existingRegistry,
    selectedWorkspaceName,
    importedWorkspace.label
  );

  // 7. Prompt for local paths for each imported repo
  const reposWithPaths = await promptRepoPaths(
    importedWorkspace.repos,
    existingRegistry?.workspaces?.[targetWorkspace.name]?.repos ?? []
  );

  // 8. Merge and save
  const mergedRegistry = mergeRegistry(
    existingRegistry,
    targetWorkspace,
    reposWithPaths,
    imported.groups ?? {},
    imported.tags ?? {}
  );

  await saveRegistry(destination.path, mergedRegistry);

  const savedCount = reposWithPaths.filter((r) => r.path).length;
  const skippedCount = reposWithPaths.filter((r) => !r.path).length;

  console.log(
    `\n✓ Saved ${savedCount} repos to ${destination.path} (workspace: ${targetWorkspace.name})` +
    (skippedCount > 0 ? ` — ${skippedCount} skipped` : '')
  );
}
```

