4. Implement `promptTargetWorkspace()` helper:
```ts
interface TargetWorkspace {
  name: string;
  label?: string;
  isNew: boolean;
}

async function promptTargetWorkspace(
  existingRegistry: ReposRegistry | null,
  suggestedName: string,
  suggestedLabel?: string
): Promise<TargetWorkspace> {
  const existingWorkspaces = existingRegistry?.workspaces ?? {};
  const existingNames = Object.keys(existingWorkspaces);

  if (existingNames.length === 0) {
    // No existing workspaces — create new with suggested name
    return { name: suggestedName, label: suggestedLabel, isNew: true };
  }

  const choices = [
    ...existingNames.map((name) => ({
      name: `${name} (existing — ${existingWorkspaces[name].repos.length} repos, will merge)`,
      value: { name, isNew: false as const },
    })),
    {
      name: '[Create new workspace]',
      value: { name: '', isNew: true as const },
    },
  ];

  const selection = await select({
    message: 'Target workspace:',
    choices,
  });

  if (selection.isNew) {
    const name = await input({
      message: 'New workspace name:',
      default: suggestedName,
      validate: (val) => {
        if (!val.trim()) return 'Workspace name is required';
        if (existingNames.includes(val)) return 'Workspace already exists';
        return true;
      },
    });
    return { name, label: suggestedLabel, isNew: true };
  }

  return { ...selection, label: existingWorkspaces[selection.name].label };
}
```

5. Implement `promptRepoPaths()` helper:
```ts
interface RepoWithPath {
  name: string;
  path?: string;
  group: string;
  tags: string[];
}

async function promptRepoPaths(
  importedRepos: ImportedRepo[],
  existingRepos: Array<{ name: string; path: string }>
): Promise<RepoWithPath[]> {
  const existingByName = new Map(existingRepos.map((r) => [r.name, r.path]));
  const result: RepoWithPath[] = [];

  console.log(`\nImporting ${importedRepos.length} repos:`);

  for (const repo of importedRepos) {
    const existingPath = existingByName.get(repo.name);

    if (existingPath) {
      // Existing repo — keep path, update group/tags
      console.log(`  ${repo.name}: keeping existing path (${existingPath})`);
      result.push({
        name: repo.name,
        path: existingPath,
        group: repo.group ?? 'default',
        tags: repo.tags ?? [],
      });
      continue;
    }

    // New repo — prompt for path
    const pathInput = await input({
      message: `  ${repo.name}: path?`,
      default: `~/code/${repo.name}`,
      validate: (val) => {
        if (val === 'skip' || val === '') return true;
        return true; // Allow any path, validation happens at scan time
      },
    });

    if (pathInput === 'skip' || pathInput === '') {
      console.log(`    (skipped)`);
      result.push({
        name: repo.name,
        path: undefined,
        group: repo.group ?? 'default',
        tags: repo.tags ?? [],
      });
    } else {
      result.push({
        name: repo.name,
        path: pathInput,
        group: repo.group ?? 'default',
        tags: repo.tags ?? [],
      });
    }
  }

  return result;
}
```

6. Implement `mergeRegistry()` helper:
```ts
function mergeRegistry(
  existing: ReposRegistry | null,
  targetWorkspace: TargetWorkspace,
  repos: RepoWithPath[],
  importedGroups: Record<string, { label?: string }>,
  importedTags: Record<string, { label?: string }>
): ReposRegistry {
  const base: ReposRegistry = existing ?? {
    workspaces: {},
    groups: {},
    tags: {},
  };

  // Merge repos into target workspace
  const existingWorkspaceRepos = base.workspaces[targetWorkspace.name]?.repos ?? [];
  const existingRepoNames = new Set(existingWorkspaceRepos.map((r) => r.name));

  const mergedRepos = [
    // Keep existing repos (with updated group/tags from import if name matches)
    ...existingWorkspaceRepos.map((existing) => {
      const imported = repos.find((r) => r.name === existing.name);
      if (imported) {
        return {
          ...existing,
          group: imported.group,
          tags: imported.tags,
        };
      }
      return existing;
    }),
    // Append new repos (not in existing)
    ...repos
      .filter((r) => !existingRepoNames.has(r.name) && r.path)
      .map((r) => ({
        name: r.name,
        path: r.path!,
        group: r.group,
        tags: r.tags,
      })),
  ];

  // Merge groups — append new, don't overwrite existing labels
  const mergedGroups = { ...base.groups };
  for (const [name, def] of Object.entries(importedGroups)) {
    if (!mergedGroups[name]) {
      mergedGroups[name] = def;
    }
  }

  // Merge tags — append new, don't overwrite existing labels
  const mergedTags = { ...base.tags };
  for (const [name, def] of Object.entries(importedTags)) {
    if (!mergedTags[name]) {
      mergedTags[name] = def;
    }
  }

  return {
    workspaces: {
      ...base.workspaces,
      [targetWorkspace.name]: {
        label: targetWorkspace.label ?? base.workspaces[targetWorkspace.name]?.label,
        repos: mergedRepos,
      },
    },
    groups: mergedGroups,
    tags: mergedTags,
  };
}
```

7. Implement `saveRegistry()` helper:
```ts
async function saveRegistry(registryPath: string, registry: ReposRegistry): Promise<void> {
  // Ensure directory exists
  const dir = path.dirname(registryPath);
  await mkdir(dir, { recursive: true });

  // Convert to YAML
  const yamlContent = yaml.dump(registry, {
    indent: 2,
    lineWidth: 120,
    noRefs: true,
  });

  // Atomic write (tmp + rename)
  const tmpPath = registryPath + '.tmp';
  await writeFile(tmpPath, yamlContent, 'utf-8');
  const { rename } = await import('node:fs/promises');
  await rename(tmpPath, registryPath);
}
```

