export async function exportWorkspace(): Promise<void> {
  // 1. Detect git root for project-level registry discovery
  const gitRoot = await detectGitRoot();

  // 2. Load all registries (global + project if applicable)
  const registries = await loadAllRegistries(gitRoot);

  // 3. Collect all workspaces with source info
  const workspaceChoices = collectWorkspaceChoices(registries);

  // 4. Handle edge cases
  if (workspaceChoices.length === 0) {
    console.error('No workspaces found. Create a repos.yml file first.');
    process.exitCode = 1;
    return;
