  } else {
    selectedWorkspace = await promptWorkspaceSelection(workspaceChoices);
  }

  // 6. Build exportable format (strip paths)
  const exported = buildExportableRegistry(selectedWorkspace, registries);

  // 7. Output YAML to stdout
  const yamlOutput = yaml.dump(exported, { 
    indent: 2, 
    lineWidth: -1,
    noRefs: true,
    sortKeys: false
  });
  console.log(yamlOutput);
}
