interface WorkspaceChoice {
  name: string;
  label?: string;
  repoCount: number;
  sourceType: 'global' | 'project';
  sourcePath: string;
  registry: ReposRegistry;
}

function collectWorkspaceChoices(registries: RegistrySource[]): WorkspaceChoice[] {
  const choices: WorkspaceChoice[] = [];

  for (const source of registries) {
    for (const [workspaceName, workspace] of Object.entries(source.registry.workspaces)) {
      choices.push({
        name: workspaceName,
        label: workspace.label,
        repoCount: workspace.repos.length,
        sourceType: source.type,
        sourcePath: source.path,
        registry: source.registry,
      });
    }
  }

  return choices;
}
