async function promptWorkspaceSelection(choices: WorkspaceChoice[]): Promise<WorkspaceChoice> {
  // Group choices by source type for display
  const globalChoices = choices.filter(c => c.sourceType === 'global');
  const projectChoices = choices.filter(c => c.sourceType === 'project');

  const selectOptions = [];

  if (globalChoices.length > 0) {
    selectOptions.push({ value: null, name: `Global (~/.agentx/repos.yml)`, disabled: true });
    for (const choice of globalChoices) {
      selectOptions.push({
        value: choice,
        name: `  ${choice.name}${choice.label ? ` (${choice.label})` : ''} — ${choice.repoCount} repos`,
      });
    }
  }

  if (projectChoices.length > 0) {
    selectOptions.push({ value: null, name: `Project (${projectChoices[0].sourcePath})`, disabled: true });
    for (const choice of projectChoices) {
      selectOptions.push({
        value: choice,
        name: `  ${choice.name}${choice.label ? ` (${choice.label})` : ''} — ${choice.repoCount} repos`,
      });
    }
  }

  return await select({
    message: 'Select workspace to export:',
    choices: selectOptions.filter(o => o.value !== null),
  });
}
