5. Implement `buildExportableRegistry()` to strip paths:
```ts
function buildExportableRegistry(
  workspace: WorkspaceChoice, 
  registries: RegistrySource[]
): ExportedRegistry {
  const sourceRegistry = workspace.registry;
  const workspaceData = sourceRegistry.workspaces[workspace.name];

  // Strip 'path' field from each repo
  const exportableRepos: ExportableRepo[] = workspaceData.repos.map(repo => {
    const exportable: ExportableRepo = { name: repo.name };

    // Only include group if not default
    if (repo.group && repo.group !== 'default') {
      exportable.group = repo.group;
    }

    // Only include tags if non-empty
    if (repo.tags && repo.tags.length > 0) {
      exportable.tags = repo.tags;
    }

    return exportable;
  });

  const exported: ExportedRegistry = {
    workspaces: {
      [workspace.name]: {
        ...(workspaceData.label && { label: workspaceData.label }),
        repos: exportableRepos,
      },
    },
  };

  // Include groups and tags from source registry if present
  if (sourceRegistry.groups && Object.keys(sourceRegistry.groups).length > 0) {
    exported.groups = sourceRegistry.groups;
  }

  if (sourceRegistry.tags && Object.keys(sourceRegistry.tags).length > 0) {
    exported.tags = sourceRegistry.tags;
  }

  return exported;
}
```

